-- ============================================================
-- SMARTSHORE HCM — REAL DATA (generated from skilltrack JSON)
-- Run in Supabase SQL Editor AFTER running schema_v2.sql
-- ============================================================

-- Enable uuid extension if not already enabled
CREATE EXTENSION IF NOT EXISTS "pgcrypto";

-- ================================================================
-- DROP & RECREATE TABLES (UUID-based schema)
-- ================================================================

DROP TABLE IF EXISTS assignments      CASCADE;
DROP TABLE IF EXISTS employee_skills  CASCADE;
DROP TABLE IF EXISTS employee_projects CASCADE;
DROP TABLE IF EXISTS projects         CASCADE;
DROP TABLE IF EXISTS employees        CASCADE;
DROP TABLE IF EXISTS board_tasks      CASCADE;
DROP TABLE IF EXISTS task_assignees   CASCADE;
DROP TABLE IF EXISTS task_tags        CASCADE;
DROP TABLE IF EXISTS weekly_utilization CASCADE;

CREATE TABLE employees (
  id             UUID PRIMARY KEY,
  name           TEXT NOT NULL,
  initials       TEXT NOT NULL,
  role           TEXT NOT NULL DEFAULT '',
  email          TEXT DEFAULT '',
  capacity_hours INTEGER DEFAULT 40,
  color          TEXT DEFAULT '#6366f1',
  created_at     TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE projects (
  id         UUID PRIMARY KEY,
  name       TEXT NOT NULL,
  client     TEXT DEFAULT '',
  color      TEXT DEFAULT '#3b82f6',
  status     TEXT DEFAULT 'active',
  start_date DATE,
  end_date   DATE,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE employee_skills (
  id          UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  employee_id UUID REFERENCES employees(id) ON DELETE CASCADE,
  skill_name  TEXT    NOT NULL,
  skill_level INTEGER DEFAULT 1,
  skill_order INTEGER DEFAULT 0
);

CREATE TABLE assignments (
  id           UUID PRIMARY KEY,
  employee_id  UUID REFERENCES employees(id) ON DELETE CASCADE,
  project_id   UUID REFERENCES projects(id)  ON DELETE CASCADE,
  week_start   DATE    NOT NULL,
  hours        INTEGER NOT NULL DEFAULT 0,
  actual_hours INTEGER NOT NULL DEFAULT 0
);

-- ── RLS (open access — add auth later) ──────────────────────────
ALTER TABLE employees      ENABLE ROW LEVEL SECURITY;
ALTER TABLE projects       ENABLE ROW LEVEL SECURITY;
ALTER TABLE employee_skills ENABLE ROW LEVEL SECURITY;
ALTER TABLE assignments    ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS anon_all ON employees;
DROP POLICY IF EXISTS anon_all ON projects;
DROP POLICY IF EXISTS anon_all ON employee_skills;
DROP POLICY IF EXISTS anon_all ON assignments;

CREATE POLICY anon_all ON employees      FOR ALL TO anon USING (true) WITH CHECK (true);
CREATE POLICY anon_all ON projects       FOR ALL TO anon USING (true) WITH CHECK (true);
CREATE POLICY anon_all ON employee_skills FOR ALL TO anon USING (true) WITH CHECK (true);
CREATE POLICY anon_all ON assignments    FOR ALL TO anon USING (true) WITH CHECK (true);


